1342	// Shuffle array using Fisher-Yates with crypto.getRandomValues when available (avoids same order every session)
1343	function shuffleArray(array) {
1344	  const shuffled = [...array];
1345	  const n = shuffled.length;
1346	  const getRandom = (max) => {
1347	    if (typeof crypto !== 'undefined' && crypto.getRandomValues) {
1348	      const arr = new Uint32Array(1);
1349	      crypto.getRandomValues(arr);
1350	      return (arr[0] / 0xffffffff) * max;
1351	    }
1352	    return Math.random() * max;
1353	  };
1354	  for (let i = n - 1; i > 0; i--) {
1355	    const j = Math.floor(getRandom(i + 1));
1356	    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
1357	  }
1358	  return shuffled;
1359	}
